// Basic snapping function
function snapToInteger(value, threshold = 0.1) {
  const rounded = Math.round(value);
  const distance = Math.abs(value - rounded);

  if (distance < threshold) {
    return rounded;
  }
  return value;
}

// Pythagorean snapping
function snapToPythagorean(x, y, threshold = 0.1) {
  const triples = [
    {a: 3, b: 4, c: 5},
    {a: 5, b: 12, c: 13},
    {a: 8, b: 15, c: 17}
  ];

  for (const triple of triples) {
    const dist = Math.sqrt(
      Math.pow(x - triple.a, 2) + 
      Math.pow(y - triple.b, 2)
    );

    if (dist < threshold) {
      return { x: triple.a, y: triple.b };
    }
  }

  return { x, y };
}

