// Generate Pythagorean triples using Euclid's formula
function generateTriples(count) {
  const triples = [];
  let m = 2;

  while (triples.length < count) {
    for (let n = 1; n < m; n++) {
      // Check if coprime and not both odd
      if (gcd(m, n) === 1 && (m - n) % 2 === 1) {
        const a = m * m - n * n;
        const b = 2 * m * n;
        const c = m * m + n * n;
        triples.push({ a, b, c });
      }
    }
    m++;
  }

  return triples;
}

function gcd(a, b) {
  return b === 0 ? a : gcd(b, a % b);
}

