// Complete snapping implementation
class PythagoreanSnapper {
  constructor(threshold = 0.1) {
    this.threshold = threshold;
    this.triples = this.generateTriples(50);
  }

  snap(point) {
    let closest = null;
    let minDistance = Infinity;

    for (const triple of this.triples) {
      const distance = this.calculateDistance(
        point, 
        { x: triple.a, y: triple.b }
      );

      if (distance < this.threshold && distance < minDistance) {
        closest = { x: triple.a, y: triple.b };
        minDistance = distance;
      }
    }

    return {
      original: point,
      snapped: closest || point,
      distance: minDistance === Infinity ? 0 : minDistance,
      didSnap: closest !== null
    };
  }

  calculateDistance(p1, p2) {
    return Math.sqrt(
      Math.pow(p1.x - p2.x, 2) + 
      Math.pow(p1.y - p2.y, 2)
    );
  }

  generateTriples(count) {
    // Euclid's formula implementation
    const triples = [];
    let m = 2;

    while (triples.length < count && m < 100) {
      for (let n = 1; n < m; n++) {
        if (this.gcd(m, n) === 1 && (m - n) % 2 === 1) {
          triples.push({
            a: m * m - n * n,
            b: 2 * m * n,
            c: m * m + n * n
          });
        }
      }
      m++;
    }

    return triples;
  }

  gcd(a, b) {
    return b === 0 ? a : this.gcd(b, a % b);
  }
}

