// Threshold comparison and analysis
class ThresholdAnalyzer {
  compareThresholds(point, thresholds) {
    return thresholds.map(threshold => ({
      value: threshold,
      snaps: this.testSnap(point, threshold)
    }));
  }

  testSnap(point, threshold) {
    // Test snap at different thresholds
    const snapper = new PythagoreanSnapper(threshold);
    return snapper.snap(point);
  }

  optimalThreshold(points, targetSnapRate = 0.3) {
    // Find threshold that achieves target snap rate
    let low = 0.001;
    let high = 1.0;

    for (let i = 0; i < 20; i++) {
      const mid = (low + high) / 2;
      const snapRate = this.calculateSnapRate(points, mid);

      if (snapRate < targetSnapRate) {
        low = mid;
      } else {
        high = mid;
      }
    }

    return (low + high) / 2;
  }

  calculateSnapRate(points, threshold) {
    const snapper = new PythagoreanSnapper(threshold);
    let snapped = 0;

    for (const point of points) {
      if (snapper.snap(point).didSnap) {
        snapped++;
      }
    }

    return snapped / points.length;
  }
}

