      this.ctx.beginPath();
      this.ctx.arc(pos.x, pos.y, 6, 0, Math.PI * 2);
      this.ctx.fill();
    }
  }

  drawThresholdRegions() {
    this.ctx.fillStyle = 'rgba(34, 197, 94, 0.1)';

    for (const triple of this.snapper.triples) {
      const pos = this.worldToScreen(triple.a, triple.b);
      const radius = this.thresholdToScreen(this.snapper.threshold);

      this.ctx.beginPath();
      this.ctx.arc(pos.x, pos.y, radius, 0, Math.PI * 2);
      this.ctx.fill();
    }
  }

  drawSnapVectors() {
    this.ctx.strokeStyle = 'rgba(250, 204, 21, 0.8)';
    this.ctx.lineWidth = 2;

    for (const point of this.points) {
      if (point.didSnap) {
        const start = this.worldToScreen(point.original.x, point.original.y);
        const end = this.worldToScreen(point.snapped.x, point.snapped.y);

        this.ctx.beginPath();
        this.ctx.moveTo(start.x, start.y);
        this.ctx.lineTo(end.x, end.y);
        this.ctx.stroke();
      }
    }
  }

  worldToScreen(x, y) {
    // Convert world coordinates to screen pixels
    return {
      x: x * this.scale + this.offsetX,
      y: this.canvas.height - (y * this.scale + this.offsetY)
    };
  }
}

// Statistics tracking
class SnapStatistics {
  constructor() {
    this.snapHistory = [];
    this.distanceHistory = [];
  }

  recordSnap(snapResult) {
    this.snapHistory.push(snapResult);

    if (snapResult.didSnap) {
      this.distanceHistory.push(snapResult.distance);
    }
  }

  getSnapRate() {
    if (this.snapHistory.length === 0) return 0;

    const snapped = this.snapHistory.filter(s => s.didSnap).length;
    return (snapped / this.snapHistory.length) * 100;
  }

  getAverageDistance() {
    if (this.distanceHistory.length === 0) return 0;

    const sum = this.distanceHistory.reduce((a, b) => a + b, 0);
    return sum / this.distanceHistory.length;
  }

  getStatistics() {
    const distances = this.distanceHistory;

    if (distances.length === 0) {
      return null;
    }

    const sorted = [...distances].sort((a, b) => a - b);
    const mean = this.getAverageDistance();

    return {
      snapRate: this.getSnapRate(),
      totalPoints: this.snapHistory.length,
      snappedPoints: distances.length,
      averageDistance: mean,
      minDistance: sorted[0],
      maxDistance: sorted[sorted.length - 1],
      medianDistance: sorted[Math.floor(sorted.length / 2)],
      standardDeviation: this.calculateStdDev(mean)
    };
  }

  calculateStdDev(mean) {
    const distances = this.distanceHistory;
    const squaredDiffs = distances.map(d => Math.pow(d - mean, 2));
    const variance = squaredDiffs.reduce((a, b) => a + b, 0) / distances.length;
    return Math.sqrt(variance);
  }

  getDistribution() {
    const distances = this.distanceHistory;
    const bins = 10;
    const max = Math.max(...distances);
    const min = Math.min(...distances);
    const binSize = (max - min) / bins;

    const distribution = new Array(bins).fill(0);

    for (const d of distances) {
      const binIndex = Math.min(
        Math.floor((d - min) / binSize),
        bins - 1
      );
      distribution[binIndex]++;
    }

    return {
      bins: distribution,
      binSize,
      min,
      max
    };
  }
}

