// Multi-pass snapping system
class AdvancedSnapSystem {
  constructor() {
    this.snapPasses = [];
  }

  addSnapPass(threshold, weight = 1.0) {
    this.snapPasses.push({ threshold, weight });
  }

  multiPassSnap(point) {
    let bestResult = null;
    let bestScore = Infinity;

    for (const pass of this.snapPasses) {
      const snapper = new PythagoreanSnapper(pass.threshold);
      const result = snapper.snap(point);

      if (result.didSnap) {
        const score = result.distance / pass.weight;

        if (score < bestScore) {
          bestScore = score;
          bestResult = result;
        }
      }
    }

    return bestResult || { didSnap: false, original: point };
  }

  weightedSnap(point, weights) {
    // Snap with weighted preferences for specific triples
    let bestResult = null;
    let bestWeight = 0;

    for (const triple of this.pythagoreanTriples) {
      const distance = this.calculateDistance(point, triple);
      const weight = weights[triple.id] || 1.0;

      if (distance < this.threshold) {
        const weightedScore = distance / weight;

        if (weightedScore < bestWeight || bestResult === null) {
          bestWeight = weightedScore;
          bestResult = { triple, distance };
        }
      }
    }

    return bestResult;
  }
}

