# Performance Optimization

Efficient snapping requires careful algorithm design.

## Spatial Partitioning

Instead of checking all Pythagorean triples, use spatial data structures:

```javascript
// KD-tree for efficient nearest neighbor search
class SpatialSnapIndex {
  constructor(triples) {
    this.kdtree = this.buildKDTree(triples);
  }

  buildKDTree(points) {
    // Recursively build KD-tree
    if (points.length === 0) return null;
    if (points.length === 1) return {
      point: points[0],
      left: null,
      right: null
    };

    // Split on median
    const axis = this.chooseAxis(points);
    points.sort((a, b) => a[axis] - b[axis]);
    const median = Math.floor(points.length / 2);

    return {
      point: points[median],
      left: this.buildKDTree(points.slice(0, median)),
      right: this.buildKDTree(points.slice(median + 1))
    };
  }

  findNearest(point, threshold) {
    return this.searchNearest(this.kdtree, point, threshold);
  }

  searchNearest(node, point, threshold, best = null) {
    if (!node) return best;

    const distance = this.calculateDistance(point, node.point);

    if (distance < threshold && (best === null || distance < best.distance)) {
      best = { point: node.point, distance };
    }

    // Prune branches that can't contain better points
    const axis = this.chooseAxis([node.point]);
    const diff = point[axis] - node.point[axis];

    if (diff < 0) {
      best = this.searchNearest(node.left, point, threshold, best);
      if (diff * diff < threshold * threshold) {
        best = this.searchNearest(node.right, point, threshold, best);
      }
    } else {
      best = this.searchNearest(node.right, point, threshold, best);
      if (diff * diff < threshold * threshold) {
        best = this.searchNearest(node.left, point, threshold, best);
      }
    }

    return best;
  }
}

