// Caching and memoization
class OptimizedSnapSystem {
  constructor() {
    this.cache = new Map();
    this.spatialIndex = null;
    this.triples = [];
  }

  initialize(triples) {
    this.triples = triples;
    this.spatialIndex = new SpatialSnapIndex(triples);
  }

  snap(point, threshold) {
    // Check cache first
    const cacheKey = this.getCacheKey(point, threshold);

    if (this.cache.has(cacheKey)) {
      return this.cache.get(cacheKey);
    }

    // Use spatial index for efficient search
    const result = this.spatialIndex.findNearest(point, threshold);

    // Cache the result
    this.cache.set(cacheKey, result);

    return result;
  }

  getCacheKey(point, threshold) {
    // Round point to avoid cache misses due to precision
    const precision = 6;
    return `${point.x.toFixed(precision)},${point.y.toFixed(precision)},${threshold}`;
  }

  clearCache() {
    this.cache.clear();
  }

  getCacheStats() {
    return {
      size: this.cache.size,
      hitRate: this.calculateHitRate()
    };
  }
}

// Batch processing
function batchSnap(points, threshold) {
  // Process multiple points efficiently
  const results = [];

  for (const point of points) {
    results.push(snapToPythagorean(point, threshold));
  }

  return results;
}

// Parallel processing (with Web Workers)
function parallelSnap(points, threshold, numWorkers = 4) {
  const chunkSize = Math.ceil(points.length / numWorkers);
  const chunks = [];

  for (let i = 0; i < points.length; i += chunkSize) {
    chunks.push(points.slice(i, i + chunkSize));
  }

  return Promise.all(
    chunks.map(chunk => 
      snapInWorker(chunk, threshold)
    )
  ).then(results => results.flat());
}

