// Real-world snapping framework
class UniversalSnapper {
  constructor(config) {
    this.snapTargets = config.targets;
    this.threshold = config.threshold;
    this.strategy = config.strategy || 'nearest';
  }

  snap(value) {
    switch (this.strategy) {
      case 'nearest':
        return this.snapNearest(value);
      case 'ceil':
        return this.snapCeil(value);
      case 'floor':
        return this.snapFloor(value);
      case 'round':
        return this.snapRound(value);
      default:
        return value;
    }
  }

  snapNearest(value) {
    let closest = null;
    let minDist = Infinity;

    for (const target of this.snapTargets) {
      const dist = Math.abs(value - target);

      if (dist < this.threshold && dist < minDist) {
        closest = target;
        minDist = dist;
      }
    }

    return closest !== null ? closest : value;
  }

  snapCeil(value) {
    for (const target of this.snapTargets) {
      if (target >= value && target - value < this.threshold) {
        return target;
      }
    }
    return value;
  }

  snapFloor(value) {
    for (const target of this.snapTargets) {
      if (target <= value && value - target < this.threshold) {
        return target;
      }
    }
    return value;
  }
}

